"use strict";(globalThis.webpackChunkknoweledge=globalThis.webpackChunkknoweledge||[]).push([[81],{6637:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/tenderwell-knowledge/docs/getting-started","label":"Getting started","docId":"getting-started","unlisted":false},{"type":"category","label":"Accounts","items":[{"type":"link","href":"/tenderwell-knowledge/docs/Accounts/Registration","label":"How to Register","docId":"Accounts/Registration","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Accounts/Authentication","label":"How to authenticate","docId":"Accounts/Authentication","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/UserProfile","label":"User Profile","docId":"UserProfile","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Accounts/Team","label":"Team Management","docId":"Accounts/Team","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Accounts/Billing","label":"Billing","docId":"Accounts/Billing","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Tenders","items":[{"type":"link","href":"/tenderwell-knowledge/docs/Tenders/Search","label":"Tender Search","docId":"Tenders/Search","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Tenders/TenderDetails","label":"Tender Details","docId":"Tenders/TenderDetails","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Tenders/Bookmarks","label":"Bookmarks","docId":"Tenders/Bookmarks","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Tenders/SavedSearches","label":"Saved Searches","docId":"Tenders/SavedSearches","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Tenders/TenderAlerts","label":"Tender Alerts","docId":"Tenders/TenderAlerts","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Tenders/BulkExport","label":"Bulk Export","docId":"Tenders/BulkExport","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Organizations","items":[{"type":"link","href":"/tenderwell-knowledge/docs/Organizations/Search","label":"Organization Search","docId":"Organizations/Search","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Organizations/Details","label":"Organization Details","docId":"Organizations/Details","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","href":"/tenderwell-knowledge/docs/Translation","label":"Translation","docId":"Translation","unlisted":false},{"type":"category","label":"Plans","items":[{"type":"link","href":"/tenderwell-knowledge/docs/Plans/PlansAndSubscriptions","label":"Plans and Subscriptions","docId":"Plans/PlansAndSubscriptions","unlisted":false},{"type":"link","href":"/tenderwell-knowledge/docs/Plans/Payments","label":"Payments","docId":"Plans/Payments","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"Accounts/Authentication":{"id":"Accounts/Authentication","title":"How to authenticate","description":"Tenderwell offers multiple authentication options. The login method depends on your registration method. So if you registered with Google then you should also login with Google. The same applies for the other methods.","sidebar":"tutorialSidebar"},"Accounts/Billing":{"id":"Accounts/Billing","title":"Billing","description":"If you purchased a subscription to a paid plan directly from the Tenderwell website then you can view and download the payment invoices from the Billing page","sidebar":"tutorialSidebar"},"Accounts/Registration":{"id":"Accounts/Registration","title":"How to Register","description":"On Tenderwell we offer multiple ways to create accounts. You can opt between using SSO solutions such as Google or Azure, DevelopmentAid or the Registration form.","sidebar":"tutorialSidebar"},"Accounts/Team":{"id":"Accounts/Team","title":"Team Management","description":"All personal data shown in the screenshots below has been edited for privacy and demonstration purposes. Please note that you cannot create accounts with fake data\u2014your email address must be verified to activate your account.","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting started","description":"Welcome to the Tenderwell knowledge base. This space will hold product documentation, tutorials, howtos, and other helpful resources for Tenderwell.","sidebar":"tutorialSidebar"},"Organizations/Details":{"id":"Organizations/Details","title":"Organization Details","description":"When you click on an organization from the search results, you\'ll see a detailed page with comprehensive information about that specific organization. This page brings together all available data\u2014from basic details to contact information and related tenders\u2014so you can evaluate potential buyers, suppliers, or contracting authorities.","sidebar":"tutorialSidebar"},"Organizations/Search":{"id":"Organizations/Search","title":"Organization Search","description":"The organization search engine helps you find buyers, contracting authorities, and suppliers across millions of organizations. You can search using free text, apply specific filters, or combine multiple criteria to narrow down results.","sidebar":"tutorialSidebar"},"Plans/Payments":{"id":"Plans/Payments","title":"Payments","description":"You can use Tenderwell for free to get some limited information about tenders and organizations.","sidebar":"tutorialSidebar"},"Plans/PlansAndSubscriptions":{"id":"Plans/PlansAndSubscriptions","title":"Plans and Subscriptions","description":"Visitors without an account have limited possibilities on Tenderwell. Once you create an account on Tenderwell you automatically are assigned a free plan.","sidebar":"tutorialSidebar"},"Tenders/Bookmarks":{"id":"Tenders/Bookmarks","title":"Bookmarks","description":"Bookmarks let you save tenders for quick access later. This is useful when you want to keep track of interesting opportunities without creating formal alerts or saved searches.","sidebar":"tutorialSidebar"},"Tenders/BulkExport":{"id":"Tenders/BulkExport","title":"Bulk Export","description":"Bulk Export allows you to export multiple tenders at once from your search results to an Excel file. Instead of viewing tenders one by one, you can select multiple tenders and download them together in a single file. This makes it easy to analyze opportunities offline, share with your team, or import into your project management systems.","sidebar":"tutorialSidebar"},"Tenders/SavedSearches":{"id":"Tenders/SavedSearches","title":"Saved Searches","description":"Saved Searches let you store your filter combinations for quick access later. Instead of selecting the same filters repeatedly, save them once and reuse them whenever you need.","sidebar":"tutorialSidebar"},"Tenders/Search":{"id":"Tenders/Search","title":"Tender Search","description":"The tender search engine helps you find relevant opportunities by filtering through millions of tenders. You can search using free text, apply specific filters, or combine multiple criteria to narrow down results.","sidebar":"tutorialSidebar"},"Tenders/TenderAlerts":{"id":"Tenders/TenderAlerts","title":"Tender Alerts","description":"Tender Alerts automatically notify you via email when new tenders match your search criteria. Instead of checking the platform daily, set up alerts and receive updates directly in your inbox.","sidebar":"tutorialSidebar"},"Tenders/TenderDetails":{"id":"Tenders/TenderDetails","title":"Tender Details","description":"When you click on a tender from the search results, you\'ll see a detailed page with comprehensive information about that specific opportunity. This page brings together all available data\u2014from basic details to documents and awards\u2014so you can evaluate whether the tender matches your business needs.","sidebar":"tutorialSidebar"},"Translation":{"id":"Translation","title":"Translation","description":"Tenderwell provides an integrated translation feature that allows you to read tenders and organization information in your preferred language. Whether you\'re browsing search results or viewing detailed pages, you can instantly translate content without leaving the platform.","sidebar":"tutorialSidebar"},"UserProfile":{"id":"UserProfile","title":"User Profile","description":"All personal data shown in the screenshots below has been edited for privacy and demonstration purposes. Please note that you cannot create accounts with fake data\u2014your email address must be verified to activate your account.","sidebar":"tutorialSidebar"}}}}')}}]);